    "database": "ercot_db",
    "query": "SELECT \n    COUNT(*) as total_intervals,\n    AVG(CASE WHEN rt.lmp - da.lmp > 0 THEN rt.lmp - da.lmp ELSE 0 END) as avg_positive_diff,\n    AVG(CASE WHEN da.lmp - rt.lmp > 0 THEN da.lmp - rt.lmp ELSE 0 END) as avg_negative_diff,\n    MAX(rt.lmp - da.lmp) as max_positive_diff,\n    MIN(rt.lmp - da.lmp) as min_negative_diff\nFROM ercot_lmp da\nJOIN ercot_lmp rt ON da.timestamp = rt.timestamp \n    AND da.zone_name = rt.zone_name \n    AND da.zone_type = rt.zone_type\n    AND da.is_day_ahead = true\n    AND rt.is_day_ahead = false\nWHERE da.zone_name = 'west' \n    AND da.zone_type = 'hub'\n    AND da.timestamp >= '2020-01-01'\n    AND da.timestamp < '2021-01-01'",
